productCreate.query:
#graphql
  mutation ProductOptionsReorderValidationCreateProduct($product: ProductCreateInput!) {
    productCreate(product: $product) {
      product {
        id
        title
      }
      userErrors {
        field
        message
      }
    }
  }

setupOptions.query:
#graphql
  mutation ProductOptionsReorderValidationSetupOptions($productId: ID!, $options: [OptionCreateInput!]!) {
    productOptionsCreate(productId: $productId, options: $options) {
      product {

  id
  options {
    id
    name
    position
    values
    optionValues {
      id
      name
      hasVariants
    }
  }
  variants(first: 10) {
    nodes {
      id
      title
      selectedOptions {
        name
        value
      }
    }
  }

      }
      userErrors {

  field
  message
  code

      }
    }
  }

setupVariants.query:
#graphql
  mutation ProductOptionsReorderValidationSetupVariants(
    $productId: ID!
    $variants: [ProductVariantsBulkInput!]!
  ) {
    productVariantsBulkCreate(productId: $productId, variants: $variants) {
      product {

  id
  options {
    id
    name
    position
    values
    optionValues {
      id
      name
      hasVariants
    }
  }
  variants(first: 10) {
    nodes {
      id
      title
      selectedOptions {
        name
        value
      }
    }
  }

      }
      productVariants {
        id
        title
        selectedOptions {
          name
          value
        }
      }
      userErrors {

  field
  message
  code

      }
    }
  }

